policies:
@rule_id("base_permit")
permit (principal, action, resource);
@tier("hard") @rule_id("read_only_forbid_write")
forbid (principal, action == Agent::Action::"invoke_tool", resource == Agent::Tool::"Write") when { context.read_only == true };
@tier("hard") @rule_id("read_only_forbid_edit")
forbid (principal, action == Agent::Action::"invoke_tool", resource == Agent::Tool::"Edit") when { context.read_only == true };
